import java.io.*;

public class SecureCommandExecutionExample {
    public static void main(String[] args) {
        try {
            // Simulating user input - This should ideally come from user input
            String userInput = "example.txt; ls";

            // Secure code - Use ProcessBuilder to safely execute commands
            ProcessBuilder processBuilder = new ProcessBuilder("cat", userInput);
            Process process = processBuilder.start();

            // Read and print the output of the command
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

